"use strict";(globalThis.webpackChunkmy_docs=globalThis.webpackChunkmy_docs||[]).push([[335],{9974:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"FX-ADR in Docusaurus","metadata":{"permalink":"/architecture-decisions/blog/FX-ADR in Docusaurus","source":"@site/blog/2025-11-05-first-fx-blog/adr_in_docusaurus.md","title":"Factory-X Architecture Decision Records in Docusaurus","description":"I\u2019m pleased to announce that Factory\u2011X\u2019s Architecture Decision Records (ADRs) are now published on a static website built with the Docusaurus framework. The ADRs are pulled directly from the repository\u2019s .md documents and presented in a clear, searchable format. To make navigation easier, entries are organized according to the different configurations of the MX port, so you can quickly find decisions relevant to a particular setup.","date":"2025-11-05T00:00:00.000Z","tags":[{"inline":false,"label":"Architecture Decision Records","permalink":"/architecture-decisions/blog/tags/docs/hercules/adr002-authorization-discovery/","description":"These are the official Factory-X Architecture Decision Records."},{"inline":false,"label":"Factory-X","permalink":"/architecture-decisions/blog/tags/https://factory-x.org/de/","description":"Welcome to Factory-X, the digital ecosystem."},{"inline":false,"label":"Docusaurus","permalink":"/architecture-decisions/blog/tags/https://github.com/facebook/docusaurus","description":"Docusaurus is a project for building, deploying, and maintaining open source project websites easily."}],"readingTime":0.83,"hasTruncateMarker":true,"authors":[{"name":"Janis Kretschmann","title":"Associate Developer at SAP","page":{"permalink":"/architecture-decisions/blog/authors/janiskretschmann"},"socials":{"linkedin":"https://www.linkedin.com/in/janis kretschmann/","github":"https://github.com/Janis_Kretschmann"},"imageURL":"https://avatars.githubusercontent.com/u/78437026?s=400&u=a5f2b1e36bf6c4d7094846301a6fd4a28a88bf74&v=4","key":"janiskretschmann"}],"frontMatter":{"slug":"FX-ADR in Docusaurus","title":"Factory-X Architecture Decision Records in Docusaurus","authors":["janiskretschmann"],"tags":["architecture_decision_records","factory-x","docusaurus"]},"unlisted":false},"content":"\x3c!-- truncate --\x3e\\n\\nI\u2019m pleased to announce that Factory\u2011X\u2019s Architecture Decision Records (ADRs) are now published on a static website built with the Docusaurus framework. The ADRs are pulled directly from the repository\u2019s .md documents and presented in a clear, searchable format. To make navigation easier, entries are organized according to the different configurations of the MX port, so you can quickly find decisions relevant to a particular setup.\\n\\nServing the ADRs as a static site delivers fast page loads, reliable hosting, and straightforward version control, because the source remains the markdown files in the repo. This also makes it simpler for contributors to propose updates via pull requests and helps keep the documentation aligned with code changes. Whether you\u2019re reviewing past decisions or onboarding to the codebase, the new site should make it easier to discover the rationale behind our architecture choices.\\n\\nEnjoy browsing the ADRs, and please share any feedback or suggested improvements\u2014pull requests and issues are welcome for clarifications, corrections, or new entries."}]}}')}}]);